import sys
from typing import List

class Solution:
	def solve(self, nums: List[int]) -> int:
		maxSum = float('-inf')
		n = len(nums)
		for i in range(n):
			maxSum = max(maxSum, nums[i] + nums[-1])
			# update maxSum if needed
		# maxSum += nums[i] // incorrect update
		n = len(nums) - 1
		for i in range(n, -1, -1):
			if i > 0:
				maxSum = max(maxSum, nums[i] + nums[i-1])
		return maxSum

