// cpp solution
#include <iostream>
#include <vector>

class Solution {
public:
	int solve(std::vector<int>& nums) {
		int maxSum = INT_MIN;
		int n = nums.size();
		for (int i = 0; i < n; i++) {
			maxSum = std::max(maxSum, nums[i] + nums[n-1]);
			// update maxSum if needed
			// maxSum += nums[i] // incorrect update
		}
		return maxSum;
	}
};
